// Filter profiles by follower count and map to outreach tracker columns
const MIN_FOLLOWERS = 200;
const MAX_FOLLOWERS = 10000;

const results = [];

for (const item of $input.all()) {
  const profile = item.json;

  if (!profile.username) continue;

  const followers = profile.followersCount || profile.followers || 0;
  if (followers < MIN_FOLLOWERS || followers > MAX_FOLLOWERS) continue;

  // Determine type (industry)
  const category = (profile.businessCategoryName || '').toLowerCase();
  const bio = (profile.biography || '').toLowerCase();

  let type = 'Other';
  if (category.includes('restaurant') || category.includes('cafe') || category.includes('food') ||
      bio.includes('restaurant') || bio.includes('cafe') || bio.includes('coffee')) {
    type = 'Restaurant / Cafe';
  } else if (category.includes('beauty') || category.includes('aesthetic') || category.includes('clinic') ||
             category.includes('skin') || bio.includes('aesthetic') || bio.includes('beauty clinic') ||
             bio.includes('skin clinic')) {
    type = 'Beauty / Aesthetics';
  }

  // Try to extract a London location signal from bio
  let location = 'London';
  const locationMatch = bio.match(/([a-z\s]+),?\s*london/i) || bio.match(/london[,\s]+([a-z\s]+)/i);
  if (locationMatch) {
    location = locationMatch[0].trim().replace(/\n/g, ' ').substring(0, 50);
  }

  // Last post date
  const lastPost = profile.latestIgtvVideo?.timestamp ||
                   profile.latestPost?.timestamp ||
                   profile.postsTimelineList?.[0]?.timestamp || '';
  const lastPostDate = lastPost ? new Date(lastPost).toISOString().split('T')[0] : '';

  results.push({
    json: {
      'Business Name': profile.fullName || profile.username,
      'Type': type,
      'Location': location,
      'Instagram Handle': '@' + profile.username,
      'Followers': followers,
      'Last Post': lastPostDate,
      'Problem Identified': '',
      'First Contact Date': '',
      'Channel': 'Instagram DM',
      'Message Sent': '',
      'Response': '',
      'Status': 'New Lead',
      'Follow Up Date': '',
      'Notes': (profile.biography || '').substring(0, 150)
    }
  });
}

// Deduplicate within this batch
const seen = new Set();
return results.filter(r => {
  const h = r.json['Instagram Handle'].toLowerCase();
  if (seen.has(h)) return false;
  seen.add(h);
  return true;
});

// Deduplicate against existing sheet rows using Instagram Handle
const newLeads = $('Filter & Format Leads').all();
const existingRows = $('Get Existing Leads').all();

const existingHandles = new Set(
  existingRows.map(r => (r.json['Instagram Handle'] || '').toLowerCase())
);

const fresh = newLeads.filter(lead => {
  const handle = (lead.json['Instagram Handle'] || '').toLowerCase();
  return handle && !existingHandles.has(handle);
});

console.log(`Fresh leads: ${fresh.length} of ${newLeads.length} total scraped`);
return fresh;
